#include <stdio.h>

int main() {
  FILE* file = fopen("example.txt", "w");
  if (file == NULL) {
    printf("Fayl acilmadi!\n");
    return 1;
  }
  fprintf(file, "Salam, Dunya!\n");
  fclose(file);
  return 0;
}
// Output (example.txt faylına yazılır):
// Salam, Dunya!

#include <stdio.h>

int main() {
  FILE* file = fopen("data.txt", "w");
  if (file == NULL) {
    printf("Fayl acilmadi!\n");
    return 1;
  }
  fprintf(file, "ID: %d, Ad: %s\n", 1, "Ali");
  fputs("Bu bir setirdir.\n", file);
  fclose(file);
  return 0;
}
// Output (data.txt faylına yazılır):
// ID: 1, Ad: Ali
// Bu bir setirdir.

#include <stdio.h>

int main() {
  FILE* file = fopen("data.txt", "r");
  if (file == NULL) {
    printf("Fayl acilmadi!\n");
    return 1;
  }
  int id;
  char name[50];
  fscanf(file, "ID: %d, Ad: %s", &id, name);
  printf("Oxunan: ID: %d, Ad: %s\n", id, name);
  char line[100];
  fgets(line, 100, file);
  printf("Oxunan setir: %s", line);
  fclose(file);
  return 0;
}
// Output (data.txt faylı əvvəlki nümunədən oxunarsa):
// Oxunan: ID: 1, Ad: Ali
// Oxunan setir: Bu bir setirdir.

